#!/usr/bin/env node
/**
 * Validate every `examples[]` entry in data/*.json against the fixed format
 * defined in docs/example-format-spec.md.
 *
 * Hard errors (fail --strict) — apply to BOTH vocab and grammar:
 *   - example is not an object / sentence is empty
 *   - missing `chinese` translation
 *   - `{kanji|reading}` or `【...】` markup is unbalanced / unparseable
 *   - grammar item with zero examples
 *
 * Length / sentence-count / ending rules are CATEGORY-AWARE:
 *   - Vocabulary examples are (re)generated by us to a tight everyday-sentence
 *     spec, so over-length / bad-ending / >2-examples are ERRORS for vocab.
 *   - Grammar examples are hand-authored teaching material that legitimately
 *     uses longer compound sentences and inline pedagogical notes
 *     (（原句：…）, →…説明, 【説明】). For grammar these are WARNINGS only, and
 *     length is measured on the "core" sentence with those notes stripped.
 *
 * It does NOT check per-level vocabulary/grammar over-scoping — that requires a
 * level word list and is a human / external-tool review step (see the spec).
 *
 * Usage:
 *   node scripts/validate-examples.cjs           # report problems, exit 0
 *   node scripts/validate-examples.cjs --strict  # exit 1 if any error found (for CI)
 *   node scripts/validate-examples.cjs data/grammar-n5.json   # specific files
 */
const fs = require("fs");
const path = require("path");

const root = path.join(__dirname, "..");
const dataDir = path.join(root, "data");

const args = process.argv.slice(2);
const strict = args.includes("--strict");
const fileArgs = args.filter((a) => !a.startsWith("--"));

// Length ceilings (measured on the de-annotated core sentence).
const MAX_VOCAB_CHARS = 20;   // tight: vocab examples are generated to spec
const MAX_GRAMMAR_CHARS = 40; // grammar compound sentences run longer (p99≈43)
const MAX_EXAMPLES = 2;       // vocab cap; grammar uses a higher warn threshold
const MAX_GRAMMAR_EXAMPLES = 8;

/** Strip {kanji|reading} → kanji and remove 【】 markers → plain Japanese. */
function toPlain(sentence) {
  return sentence
    .replace(/\{([^|{}]+)\|[^}]+\}/g, "$1")
    .replace(/[【】]/g, "");
}

/**
 * Core sentence used for length checks: the plain sentence with inline teaching
 * annotations removed — full-width parentheticals「（原句：…）」, trailing
 * explanation chains「→…」, and meta notes already covered by 【】 stripping.
 */
function toCore(sentence) {
  return toPlain(sentence)
    .replace(/（[^）]*）/g, "")
    .replace(/→.*$/, "")
    .trim();
}

/** Validate markup balance; returns array of error strings. */
function checkMarkup(sentence) {
  const errors = [];

  // 【 / 】 balance
  const open = (sentence.match(/【/g) || []).length;
  const close = (sentence.match(/】/g) || []).length;
  if (open !== close) errors.push(`【】 不成對 (${open} open / ${close} close)`);

  // { / } balance and each {..} must contain a single |
  const braceGroups = sentence.match(/\{[^{}]*\}/g) || [];
  const rawOpen = (sentence.match(/\{/g) || []).length;
  const rawClose = (sentence.match(/\}/g) || []).length;
  if (rawOpen !== rawClose) {
    errors.push(`{} 不成對 (${rawOpen} open / ${rawClose} close)`);
  }
  for (const g of braceGroups) {
    const inner = g.slice(1, -1);
    const pipes = (inner.match(/\|/g) || []).length;
    if (pipes !== 1) errors.push(`furigana 標注 "${g}" 必須剛好一個 |`);
  }
  return errors;
}

function validateExample(ex, locator, isGrammar) {
  const problems = [];
  if (!ex || typeof ex !== "object") {
    return [{ level: "error", locator, msg: "example 不是物件" }];
  }
  if (typeof ex.sentence !== "string" || !ex.sentence.trim()) {
    problems.push({ level: "error", locator, msg: "sentence 為空" });
    return problems;
  }
  // Missing translation and broken markup are always hard errors.
  if (typeof ex.chinese !== "string" || !ex.chinese.trim()) {
    problems.push({ level: "error", locator, msg: "缺中譯 (chinese 為空)" });
  }
  for (const m of checkMarkup(ex.sentence)) {
    problems.push({ level: "error", locator, msg: m });
  }

  // Length & ending: error for vocab (generated to spec), warn for grammar.
  const sevLevel = isGrammar ? "warn" : "error";
  const maxChars = isGrammar ? MAX_GRAMMAR_CHARS : MAX_VOCAB_CHARS;
  const core = toCore(ex.sentence);
  if (core.length > maxChars) {
    problems.push({
      level: sevLevel,
      locator,
      msg: `句子過長 ${core.length} 字 (上限 ${maxChars})：「${core}」`,
    });
  }
  // Ending check uses the core sentence so trailing 説明 notes don't trip it.
  if (core && !/[。？！]$/.test(core)) {
    problems.push({ level: sevLevel, locator, msg: `句尾未以「。」「？」「！」結尾：「${core}」` });
  }
  return problems;
}

function validateFile(filePath) {
  const problems = [];
  let dataset;
  try {
    dataset = JSON.parse(fs.readFileSync(filePath, "utf8"));
  } catch (e) {
    return [{ level: "error", locator: path.basename(filePath), msg: `JSON 解析失敗：${e.message}` }];
  }
  if (!Array.isArray(dataset.data)) return problems;

  const base = path.basename(filePath);
  for (const item of dataset.data) {
    const isGrammar = !("hiragana" in item);
    const examples = Array.isArray(item.examples) ? item.examples : [];

    if (examples.length === 0) {
      if (isGrammar) {
        problems.push({ level: "error", locator: `${base}#${item.id}`, msg: "文法項目缺例句" });
      }
      continue;
    }
    // Example-count cap: error for vocab (>2), warn for grammar (>8).
    const cap = isGrammar ? MAX_GRAMMAR_EXAMPLES : MAX_EXAMPLES;
    if (examples.length > cap) {
      problems.push({
        level: isGrammar ? "warn" : "error",
        locator: `${base}#${item.id}`,
        msg: `例句 ${examples.length} 句 (上限 ${cap})`,
      });
    }
    examples.forEach((ex, i) => {
      problems.push(...validateExample(ex, `${base}#${item.id}[${i}]`, isGrammar));
    });
  }
  return problems;
}

function main() {
  const files = (fileArgs.length > 0
    ? fileArgs.map((f) => path.resolve(root, f))
    : fs.readdirSync(dataDir).filter((f) => f.endsWith(".json")).map((f) => path.join(dataDir, f))
  );

  let errors = 0;
  let warns = 0;
  for (const file of files) {
    const problems = validateFile(file);
    for (const p of problems) {
      if (p.level === "error") errors++;
      else warns++;
      const tag = p.level === "error" ? "ERROR" : "warn ";
      console.log(`[${tag}] ${p.locator}: ${p.msg}`);
    }
  }

  console.log(`\n[validate-examples] ${errors} error(s), ${warns} warning(s) across ${files.length} file(s).`);
  if (strict && errors > 0) process.exit(1);
}

main();
